    questions: [
      { id: 'gk-2024-qu-1', question: "The work must be ___ by next month.", questionZh: "这项工作下个月前必须完成___。", options: ["completed", "complete", "completing", "to complete"], correctAnswer: 0, explanation: "modal passive must be" },
      { id: 'gk-2024-qu-2', question: "It was not until he arrived home that ___ his wife.", questionZh: "直到他到家他才找到他妻子___。", options: ["he found", "I found", "we found", "she found"], correctAnswer: 0, explanation: "not until强调句 it was not until that" },
      { id: 'gk-2024-qu-3', question: "I would have called you to report the loss.", questionZh: "如果我知道这个损失，我会立即你___。", options: ["to report", "report", "reporting", "reported"], correctAnswer: 0, explanation: "would have called infinitive for purpose" },
      { id: 'gk-2024-qu-4', question: "The building whose ___ are broken is under repair.", questionZh: "窗户坏了的那座建筑正在修缮中___。", options: ["windows", "doors", "roofs", "walls"], correctAnswer: 0, explanation: "whose = possessive" },
      { id: 'gk-2024-qu-5', question: "___ you like it or not, you must follow the rules.", questionZh: "无论你是否喜欢，你必须遵守规则___。", options: ["Could", "May", "Should", "Would"], correctAnswer: 1, explanation: "may = possibility" },
      { id: 'gk-2024-qu-6', question: "The students are encouraged to solve problems ___.", questionZh: "学生们被鼓励自己解决问题___。", options: ["with themselves", "by themselves", "for themselves", "to themselves"], correctAnswer: 1, explanation: "by themselves = independently" },
      { id: 'gk-2024-qu-7', question: "I do not doubt that ___ he will succeed.", questionZh: "我不怀疑他会成功___。", options: ["he", "she", "they", "we"], correctAnswer: 0, explanation: "no doubt that clause" },
      { id: 'gk-2024-qu-8', question: "The more you read, ___ you understand.", questionZh: "你读得越多，你理解得越深___。", options: ["the more", "the most", "more", "most"], correctAnswer: 0, explanation: "the more the more comparative" },
      { id: 'gk-2024-qu-9', question: "He spoke as if he ___ everything.", questionZh: "他说起话来好像他知道一切___。", options: ["knew", "knows", "has known", "had known"], correctAnswer: 3, explanation: "as if past perfect unreal" },
      { id: 'gk-2024-qu-10', question: "The teacher demanded that everyone ___ on time.", questionZh: "老师要求每个人都要准时___。", options: ["is", "was", "be", "to be"], correctAnswer: 2, explanation: "demand should do subjunctive" },
      { id: 'gk-2024-qu-11', question: "___ the rain stops, we cannot leave.", questionZh: "雨不停，我们就无法离开___。", options: ["Unless", "If", "Because", "When"], correctAnswer: 0, explanation: "unless = if not conditional" },
      { id: 'gk-2024-qu-12', question: "She always behaves as if she ___ someone important.", questionZh: "她的行为总像是她认识某个重要人物___。", options: ["knew", "knows", "knowing", "to know"], correctAnswer: 0, explanation: "as if past subjunctive" },
      { id: 'gk-2024-qu-13', question: "This is the very book I have been looking ___", questionZh: "这正是我一直在找的的书___。", options: ["for", "after", "at", "into"], correctAnswer: 0, explanation: "look for = search" },
      { id: 'gk-2024-qu-14', question: "However ___ the problem is, we must solve it.", questionZh: "问题多困难，我们都必解决它___。", options: ["difficult", "hard", "easy", "simple"], correctAnswer: 0, explanation: "however adj no matter how" },
      { id: 'gk-2024-qu-15', question: "The boy was seen ___ the street.", questionZh: "有人看见那个男孩跑过街道___。", options: ["crossing", "cross", "to cross", "crossed"], correctAnswer: 0, explanation: "see sb doing observed" },
      { id: 'gk-2024-qu-16', question: "It is essential that everyone ___ the safety guidelines.", questionZh: "每个人了解安全准则很必要___。", options: ["understand", "understands", "to understand", "understanding"], correctAnswer: 0, explanation: "essential should do subjunctive" },
      { id: 'gk-2024-qu-17', question: "By next year, he will have ___ here for ten years.", questionZh: "到明年，他在这里就十年了___。", options: ["worked", "been working", "work", "works"], correctAnswer: 0, explanation: "by future = future perfect" },
      { id: 'gk-2024-qu-18', question: "He asked me if I ___ to the movie.", questionZh: "他问我是否想去看电影___。", options: ["go", "went", "will go", "would go"], correctAnswer: 3, explanation: "past tense indirect speech would" },
      { id: 'gk-2024-qu-19', question: "I suggest that we ___ the meeting until Friday.", questionZh: "我建议我们把会议推迟到周五___。", options: ["postpone", "postpones", "postponing", "to postpone"], correctAnswer: 0, explanation: "suggest should do subjunctive" },
      { id: 'gk-2024-qu-20', question: "As ___ is known to all, the earth is round.", questionZh: "众所周知，地球是圆的___。", options: ["it", "this", "that", "which"], correctAnswer: 0, explanation: "as引导非限制性定语从句" },
      { id: 'gk-2024-qu-21', question: "The room needs ___", questionZh: "房间需要打扫___。", options: ["cleaning", "to clean", "cleaned", "be cleaned"], correctAnswer: 0, explanation: "need doing = need to be done" },
      { id: 'gk-2024-qu-22', question: "She acted as if she had ___ met me before.", questionZh: "她表现得好像她以前从未过我___。", options: ["never", "ever", "already", "yet"], correctAnswer: 0, explanation: "as if past perfect unreal" },
      { id: 'gk-2024-qu-23', question: "He ran fast so that he ___ miss the train.", questionZh: "他跑得很快他会错过火车___。", options: ["might not", "would not", "could not", "should not"], correctAnswer: 0, explanation: "so that might could purpose" },
      { id: 'gk-2024-qu-24', question: "The teacher said that light ___ faster than sound.", questionZh: "老师告诉我们光传播得比声音快___。", options: ["travels faster than", "travel faster that", "travelled faster than", "travels more fast than"], correctAnswer: 0, explanation: "factual statement pres simple" },
      { id: 'gk-2024-qu-25', question: "I would rather you ___ tomorrow.", questionZh: "我宁愿你明天来___。", options: ["come", "came", "to come", "coming"], correctAnswer: 0, explanation: "would rather sb do" }
    ],
