      { id: 'gk-2024-zj-24', question: "I would have helped him, ___ he did not ask.", questionZh: "我会帮他的___他没有开口。", options: ["but", "except", "however", "although"], correctAnswer: 0, explanation: "but however contrast" },
      { id: 'gk-2024-zj-25', question: "He did not come to the party, which ___ was expected.", questionZh: "他没有来聚会，这是可以预期的___。", options: ["is", "was", "are", "will be"], correctAnswer: 0, explanation: "which代替整个句子 non-restrictive" }
